import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldAlert, BarChart3, Cpu, Globe, Server } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);

    // --- STATE MANAGEMENT ---
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) initializeStocks(res.data[0].holdings);
            } catch (err) { console.error("VAULT_OFFLINE"); }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            setStocks(tickers.map(t => ({ ticker: t, price: Math.floor(Math.random() * 2000) + 500, change: 0.00 })));
        } catch (e) { setStocks([]); }
    };

    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 8;
                return { ...s, price: parseFloat((s.price + move).toFixed(2)), change: parseFloat(move.toFixed(2)) };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (dir) => {
        let newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            initializeStocks(history[newIdx].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={fullScreenWrapper}>
            {/* ── TOP BAR: SYSTEM STATUS ── */}
            <div style={topBar}>
                <div style={brandSection}>
                    <Cpu size={18} color="var(--accent-primary)" />
                    <span style={brandText}>FINIFY_CORE_TERMINAL_v3.0</span>
                </div>
                <div style={statusSection}>
                    <div style={statusItem}><Globe size={12}/> REGION: PUNE_IN</div>
                    <div style={statusItem}><Server size={12}/> NODE: {activeNode?.id || '---'}</div>
                    <div style={connectionBadge(isConnected)}>
                        <Activity size={10} /> {isConnected ? 'SYSTEM_ALIVE' : 'LINK_INTERRUPT'}
                    </div>
                </div>
            </div>

            <div style={mainGrid}>
                {/* ── LEFT COLUMN: NODE CONTROL ── */}
                <div style={leftCol}>
                    <p style={sidebarLabel}>STRATEGY_SELECTOR</p>
                    <div style={navControls}>
                        <button onClick={() => navigate(1)} disabled={currentIndex === history.length - 1} style={ctrlBtn}>
                            <ChevronLeft size={16}/> PREV
                        </button>
                        <div style={nodeCounter}>{currentIndex + 1} / {history.length}</div>
                        <button onClick={() => navigate(-1)} disabled={currentIndex === 0} style={ctrlBtn}>
                            NEXT <ChevronRight size={16}/>
                        </button>
                    </div>
                    
                    <div style={activeNodeCard}>
                        <p style={labelTiny}>ACTIVE_THESIS</p>
                        <h3 style={nodeTitle}>{activeNode ? activeNode.goal : 'INITIALIZING...'}</h3>
                        <p style={nodeSummary}>{activeNode?.summary.substring(0, 180)}...</p>
                    </div>

                    <div style={auditCard}>
                        <p style={labelTiny}>RISK_AUDIT</p>
                        <div style={riskBarContainer}>
                            <div style={riskBar(activeNode?.risk_score)} />
                        </div>
                        <span style={riskVal}>{activeNode?.risk_score}% EXPOSURE</span>
                    </div>
                </div>

                {/* ── CENTER COLUMN: MARKET ANALYTICS ── */}
                <div style={centerCol}>
                    <div style={analyticsHeader}>
                        <BarChart3 size={16} color="var(--accent-primary)" />
                        <span style={labelMedium}>INSTITUTIONAL_TICKER_FEED</span>
                    </div>
                    
                    <div style={tickerGrid}>
                        {stocks.map((stock, i) => (
                            <div key={i} style={stockCard(stock.change >= 0)}>
                                <div style={cardHeader}>
                                    <span style={tickerName}>{stock.ticker}</span>
                                    <Zap size={12} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                                </div>
                                <div style={priceBig}>₹{stock.price.toLocaleString()}</div>
                                <div style={changeRow(stock.change >= 0)}>
                                    {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                    {stock.change >= 0 ? '+' : ''}{stock.change}%
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* ── RIGHT COLUMN: SHIELD & METRICS ── */}
                <div style={rightCol}>
                    <p style={sidebarLabel}>SECURITY_OVERWATCH</p>
                    <div style={metricCard}>
                        <ShieldAlert size={20} color="#ef4444" />
                        <div>
                            <p style={labelTiny}>SWAN_RESILIENCE</p>
                            <p style={metricVal}>-14.8% DRAWDOWN</p>
                        </div>
                    </div>
                    <div style={metricCard}>
                        <Zap size={20} color="#f59e0b" />
                        <div>
                            <p style={labelTiny}>SIGNAL_STRENGTH</p>
                            <p style={metricVal}>HIGH_CONFIDENCE</p>
                        </div>
                    </div>
                    
                    <div style={terminalFooter}>
                        <p style={footerText}>TERMINAL_ENCRYPTION_ACTIVE</p>
                        <p style={footerText}>PULSE_INTERVAL: 5000ms</p>
                    </div>
                </div>
            </div>
        </div>
    );
};

/* --- FULL SCREEN CSS --- */
const fullScreenWrapper = { height: '100vh', width: '100vw', background: '#07080a', color: '#fff', overflow: 'hidden', display: 'flex', flexDirection: 'column' };
const topBar = { height: '60px', borderBottom: '1px solid #1a1d23', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 2rem', background: '#0a0b0e' };
const brandSection = { display: 'flex', alignItems: 'center', gap: '10px' };
const brandText = { fontSize: '0.75rem', fontWeight: 900, letterSpacing: '0.1em', fontFamily: 'monospace' };
const statusSection = { display: 'flex', gap: '2rem', alignItems: 'center' };
const statusItem = { fontSize: '0.6rem', color: '#666', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '6px' };
const connectionBadge = (online) => ({ padding: '4px 12px', background: online ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)', color: online ? '#10b981' : '#ef4444', border: `1px solid ${online ? '#10b981' : '#ef4444'}`, borderRadius: '4px', fontSize: '0.6rem', fontWeight: 900, display: 'flex', alignItems: 'center', gap: '6px' });
const mainGrid = { display: 'grid', gridTemplateColumns: '300px 1fr 280px', flex: 1, overflow: 'hidden' };
const leftCol = { padding: '2rem', borderRight: '1px solid #1a1d23', display: 'flex', flexDirection: 'column', gap: '2rem' };
const centerCol = { padding: '2rem', overflowY: 'auto', background: 'radial-gradient(circle at top, rgba(16,185,129,0.03) 0%, transparent 70%)' };
const rightCol = { padding: '2rem', borderLeft: '1px solid #1a1d23', background: '#0a0b0e', display: 'flex', flexDirection: 'column', gap: '1.5rem' };
const sidebarLabel = { fontSize: '0.6rem', fontWeight: 900, color: '#444', letterSpacing: '0.2em', marginBottom: '1rem' };
const navControls = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: '#111318', padding: '0.8rem', borderRadius: '12px', border: '1px solid #1a1d23' };
const ctrlBtn = { background: 'none', border: 'none', color: 'var(--accent-primary)', cursor: 'pointer', fontSize: '0.65rem', fontWeight: 900, display: 'flex', alignItems: 'center' };
const nodeCounter = { fontSize: '0.7rem', fontWeight: 900, color: '#fff' };
const activeNodeCard = { padding: '1.5rem', background: 'rgba(255,255,255,0.02)', borderRadius: '16px', border: '1px solid #1a1d23' };
const nodeTitle = { fontSize: '1rem', fontWeight: 900, margin: '0.5rem 0' };
const nodeSummary = { fontSize: '0.75rem', color: '#888', lineHeight: 1.6 };
const auditCard = { padding: '1.5rem', background: '#111318', borderRadius: '16px', border: '1px solid #1a1d23' };
const labelTiny = { fontSize: '0.5rem', fontWeight: 900, color: 'var(--accent-primary)', letterSpacing: '0.1em' };
const riskBarContainer = { height: '4px', background: '#222', borderRadius: '2px', margin: '12px 0' };
const riskBar = (val) => ({ width: `${val}%`, height: '100%', background: '#10b981', boxShadow: '0 0 10px #10b981' });
const riskVal = { fontSize: '0.7rem', fontWeight: 900, color: '#fff' };
const analyticsHeader = { display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '2rem' };
const labelMedium = { fontSize: '0.75rem', fontWeight: 900, letterSpacing: '0.1em' };
const tickerGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1rem' };
const stockCard = (up) => ({ padding: '1.5rem', background: '#111318', border: '1px solid #1a1d23', borderRadius: '20px', borderLeft: `4px solid ${up ? '#10b981' : '#ef4444'}` });
const cardHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }; // FIXED MISSING DEF
const tickerName = { fontSize: '0.8rem', fontWeight: 900, color: 'var(--accent-primary)', fontFamily: 'monospace' };
const priceBig = { fontSize: '2.2rem', fontWeight: 900, margin: '0.5rem 0' };
const changeRow = (up) => ({ color: up ? '#10b981' : '#ef4444', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem', fontWeight: 900 });
const metricCard = { display: 'flex', alignItems: 'center', gap: '15px', padding: '1.2rem', background: '#111318', borderRadius: '16px', border: '1px solid #1a1d23' };
const metricVal = { fontSize: '0.85rem', fontWeight: 900, color: '#fff', marginTop: '4px' };
const terminalFooter = { marginTop: 'auto', borderTop: '1px solid #1a1d23', paddingTop: '1.5rem' };
const footerText = { fontSize: '0.55rem', color: '#444', fontFamily: 'monospace', margin: '4px 0' };

export default LiveMarketPage;
